const items = $input.all().map(i => i.json);
const freqThreshold = parseFloat($env.FATIGUE_FREQ_THRESHOLD || 3.0);

// Top 5 spenders
const topSpend = [...items].sort((a,b) => b.spend - a.spend).slice(0, 5);
// Bottom 5 by CPA (highest efficiency)
const topEfficiency = items.filter(a => a.conversions > 0).sort((a,b) => a.cpa - b.cpa).slice(0, 5);
// High frequency fatigue
const fatigue = items.filter(a => a.frequency > freqThreshold);

// Summary stats
const totalSpend = items.filter(i => i.entity_level === 'adset').reduce((s,i) => s + i.spend, 0);
const totalConversions = items.filter(i => i.entity_level === 'adset').reduce((s,i) => s + i.conversions, 0);
const avgCpa = totalConversions > 0 ? totalSpend / totalConversions : null;

return [{
  json: {
    summary: { totalSpend, totalConversions, avgCpa },
    top_spend: topSpend,
    top_efficiency: topEfficiency,
    fatigue_candidates: fatigue
  }
}];

